using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- 1. Getting strongly-typed JsonTypeInfo<T> ---

var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// Generic overload returns JsonTypeInfo<T> directly — no cast needed.
JsonTypeInfo<Person> typedInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Typed metadata for: {typedInfo.Type.Name}");
Console.WriteLine($"  Properties: {string.Join(", ", typedInfo.Properties.Select(p => p.Name))}");

// Use the typed metadata to serialize/deserialize
string json = JsonSerializer.Serialize(new Person("Alice", 30), typedInfo);
Console.WriteLine($"  Serialized: {json}");

Person? person = JsonSerializer.Deserialize(json, typedInfo);
Console.WriteLine($"  Deserialized: {person}");

// --- 2. Probing without throwing (TryGetTypeInfo) ---

// Use a source-generated context that only knows about Person.
JsonSerializerOptions limitedOptions = LimitedContext.Default.Options;

// This type IS in the context → returns true
if (limitedOptions.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
    Console.WriteLine($"\n✓ Metadata found for Person: {found!.Type.Name}");
else
    Console.WriteLine("\n✗ No metadata for Person");

// This type is NOT in the context → returns false, no exception
if (limitedOptions.TryGetTypeInfo(typeof(Order), out JsonTypeInfo? notFound))
    Console.WriteLine($"✓ Metadata found for Order: {notFound!.Type.Name}");
else
    Console.WriteLine("✗ No metadata for Order (not in the source-gen context)");

// --- Types ---

public record Person(string Name, int Age);
public record Order(int Id, decimal Total);

// Source-generated context that only includes Person
[JsonSerializable(typeof(Person))]
public partial class LimitedContext : JsonSerializerContext;

